import {AlertTriangle,Clock3,Search,X} from 'lucide-react';import {useMemo,useState} from 'react';import {Background,ReactFlow} from '@xyflow/react';import {PageHead,Status} from '../components/Common';import {useStudio} from '../store/useStudio';import type {Instance} from '../types';
export default function Monitor(){const instances=useStudio(s=>s.instances),ws=useStudio(s=>s.workflows),[filter,setFilter]=useState('all'),[selected,setSelected]=useState<Instance|null>(null);const rows=useMemo(()=>instances.filter(i=>filter==='all'||i.status===filter),[instances,filter]);return <><PageHead eyebrow="RUNTIME OPERATIONS" title="运行监控" desc={`实时追踪 ${instances.length} 个流程实例，定位超时与执行异常`} actions={<button className="secondary"><Clock3/>数据更新于 16:48</button>}/><div className="monitor-summary"><div><strong>{instances.filter(i=>i.status==='running').length}</strong><span>进行中</span></div><div><strong>{instances.filter(i=>i.status==='completed').length}</strong><span>已完成</span></div><div className="danger"><strong>{instances.filter(i=>i.status==='abnormal').length}</strong><span>异常</span></div><div className="warn"><strong>{instances.filter(i=>i.status==='timeout').length}</strong><span>已超时</span></div></div><div className="panel"><div className="filters"><label className="search"><Search/><input placeholder="搜索实例编号或申请人"/></label>{['all','abnormal','timeout','running','completed'].map(x=><button className={filter===x?'filter-active':'secondary'} onClick={()=>setFilter(x)} key={x}>{x==='all'?'全部实例':<Status value={x}/>}</button>)}</div><div className="table-wrap"><table><thead><tr><th>实例编号</th><th>申请人</th><th>业务域</th><th>当前节点</th><th>状态</th><th>提交时间</th><th>耗时</th><th>风险</th></tr></thead><tbody>{rows.slice(0,30).map(i=><tr key={i.id} onClick={()=>setSelected(i)} data-testid={`instance-${i.id}`}><td><button className="instance-link">{i.id}</button></td><td>{i.applicant}</td><td>{i.domain}</td><td>{i.currentNode}</td><td><Status value={i.status}/></td><td>{i.submittedAt}</td><td>{i.duration}</td><td><span className={`risk risk-${i.risk}`}>{i.risk==='high'?'高':i.risk==='medium'?'中':'低'}</span></td></tr>)}</tbody></table></div></div>{selected&&<Detail instance={selected} workflow={ws.find(w=>w.id===selected.workflowId)!} close={()=>setSelected(null)}/>}</>}
function Detail({instance,workflow,close}:{instance:Instance,workflow:any,close:()=>void}){const current=workflow.nodes.find((n:any)=>n.data.label===instance.currentNode)?.id;const nodes=workflow.nodes.map((n:any)=>({...n,data:{label:n.data.label},className:n.id===current?'runtime-current':'runtime-node'}));return <div className="drawer-backdrop"><aside className="instance-drawer" data-testid="instance-detail"><div className="drawer-head"><div><small>流程实例详情</small><h2>{instance.id}</h2></div><button onClick={close}><X/></button></div><div className="detail-meta"><div><small>申请人</small><b>{instance.applicant}</b></div><div><small>状态</small><Status value={instance.status}/></div><div><small>风险等级</small><b className="danger-text">高风险</b></div><div><small>累计耗时</small><b>{instance.duration}</b></div></div><section><h3>执行路径</h3><div className="runtime-flow" data-testid="runtime-flow"><ReactFlow nodes={nodes} edges={workflow.edges} fitView nodesDraggable={false} nodesConnectable={false}><Background/></ReactFlow></div></section><section><h3>执行时间线</h3><div className="timeline" data-testid="execution-timeline">{instance.timeline.map((t,k)=><div className={t.status} key={k}><span>{t.status==='current'?<AlertTriangle/>:'✓'}</span><div><b>{t.title}</b><small>{t.time} · {t.status==='current'?'当前停留':'已完成'}</small></div></div>)}</div></section></aside></div>}

